from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/reply')
def listFiles():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username', None)
    if username is None:
        raise ValueError()
    if not isinstance(username, str):
        raise TypeError()
    username = username.strip()
    if username == '' or len(username) > 32:
        raise ValueError()

    # Allow only simple usernames to prevent injection/path tricks
    if not re.fullmatch(r"[a-zA-Z0-9_]+", username):
        raise ValueError()

    home_dir = os.path.join('/home', username)

    # For predictable tests, also allow listing from controlled Test directory
